# HuiYuYuan Android Keystore Generator`n# Usage: .\scripts\generate_keystore.ps1`n`n$ErrorActionPreference = "Stop"`n`n$appDir = Join-Path $PSScriptRoot "..\huiyuyuan_app\android"`n$jksPath = Join-Path $appDir "huiyuyuan.jks"`n$keyPropsPath = Join-Path $appDir "key.properties"`n`ntry { $null = Get-Command keytool -ErrorAction Stop } catch { Write-Host "[ERROR] keytool not found. Install JDK first." -ForegroundColor Red; exit 1 }`n`nif (Test-Path $jksPath) { Write-Host "Already exists: $jksPath" -ForegroundColor Yellow; exit 0 }`n`n$storePass = Read-Host "Keystore password"`n$kp = Read-Host "Key password (Enter=same)" -AsSecureString`n$b = [Runtime.InteropServices.Marshal]::SecureStringToBSTR($kp)`n$keyPass = [Runtime.InteropServices.Marshal]::PtrToStringAuto($b)`n[Runtime.InteropServices.Marshal]::ZeroFreeBSTR($b)`nif ($keyPass -eq "") { $keyPass = $storePass }`n`n& keytool -genkeypair -v -keystore $jksPath -keyalg RSA -keysize 2048 -validity 10000 -alias huiyuyuan -storepass $storePass -keypass $keyPass -dname "CN=HuiYuYuan,OU=Dev,O=HuiYuYuan,L=Shenzhen,S=Guangdong,C=CN" 2>&1`n`n$t = "storePassword=$storePass`nkeyPassword=$keyPass`nkeyAlias=huiyuyuan`nstoreFile=../huiyuyuan.jks"`n[System.IO.File]::WriteAllText($keyPropsPath, $t, [Text.Encoding]::UTF8)`nWrite-Host "Done. Backup $jksPath safely!" -ForegroundColor Green